var STEPS=[
{icon:'fa-user',title:'Identitas Pasien'},{icon:'fa-comment-medical',title:'Keluhan Utama'},
{icon:'fa-file-medical',title:'Riwayat Penyakit'},{icon:'fa-people-group',title:'Riwayat Keluarga'},
{icon:'fa-utensils',title:'Pola Aktivitas'},{icon:'fa-stethoscope',title:'Pemeriksaan Fisik'},
{icon:'fa-flask',title:'Penunjang'},{icon:'fa-robot',title:'AI Detector'},
{icon:'fa-chart-bar',title:'Analisa Data'},{icon:'fa-hospital',title:'SDKI/SLKI/SIKI'},
{icon:'fa-bolt',title:'Prioritas'},{icon:'fa-book',title:'Literatur'}];
var curStep=0,painVal=-1,labC=0,roxC=0,_dr=[];

// Build nav
(function(){var n=document.getElementById('navl');STEPS.forEach(function(s,i){var d=document.createElement('div');d.className='ni'+(i===0?' active':'');d.innerHTML='<i class="fas '+s.icon+'"></i><span>'+s.title+'</span><span class="sn">'+(i+1)+'</span>';d.onclick=function(){goStep(i)};n.appendChild(d)})})();

function goStep(n){
if(n<0||n>=STEPS.length)return;
document.querySelectorAll('.step').forEach(function(e){e.classList.remove('active')});
curStep=n;var el=document.querySelector('.step[data-s="'+n+'"]');if(el)el.classList.add('active');
document.querySelectorAll('.ni').forEach(function(e,i){e.classList.toggle('active',i===n);if(i<n)e.classList.add('done');else e.classList.remove('done')});
document.getElementById('stitle').textContent=(n+1)+'. '+STEPS[n].title;
var p=Math.round(n/(STEPS.length-1)*100);document.getElementById('pfill').style.width=p+'%';
document.getElementById('ptext').textContent=p+'%';
window.scrollTo({top:0,behavior:'smooth'});
document.getElementById('sidebar').classList.remove('open');
document.getElementById('ovl').classList.remove('show');
if(n===1&&document.getElementById('pain-scale')&&!document.getElementById('pain-scale').children.length)buildPain();
if(n===5){calcGCS();calcIMT()}if(n===9)renderDx();if(n===10)renderPri();
}
function toggleSB(){document.getElementById('sidebar').classList.toggle('open');document.getElementById('ovl').classList.toggle('show')}
function toast(m,t){t=t||'s';var ic={s:'fa-check-circle',e:'fa-times-circle',i:'fa-info-circle'};var d=document.createElement('div');d.className='toast t-'+t;d.innerHTML='<i class="fas '+ic[t]+'"></i>'+m;document.getElementById('toast-box').appendChild(d);setTimeout(function(){d.remove()},3000)}
function gv(id){var e=document.getElementById(id);return e?e.value.trim():''}
function gcv(id){return[].slice.call(document.querySelectorAll('#'+id+' .ci.ck')).map(function(e){return e.dataset.val})}
function cc(e){var c=e.target.closest('.ci');if(!c)return;c.classList.toggle('ck');c.querySelector('input').checked=c.classList.contains('ck')}

// Clear
function clearAllData(){document.getElementById('modal-clear').style.display='flex'}
function doClear(){
document.querySelectorAll('.fi,.fta').forEach(function(e){if(!e.readOnly)e.value=''});
document.querySelectorAll('.fs').forEach(function(e){e.selectedIndex=0});
document.querySelectorAll('.ci.ck').forEach(function(e){e.classList.remove('ck');e.querySelector('input').checked=false});
painVal=-1;document.querySelectorAll('.pb.sel').forEach(function(b){b.classList.remove('sel');b.style.background='';b.style.borderColor='';b.style.color=''});
document.getElementById('lab-rows').innerHTML='';document.getElementById('rox-rows').innerHTML='';
labC=0;roxC=0;aLR();aLR();aLR();aRR();aRR();
['analisa-s','analisa-o','analisa-m'].forEach(function(id){document.getElementById(id).style.display='none'});
document.getElementById('data-s').innerHTML='';document.getElementById('data-o').innerHTML='';document.getElementById('data-masalah').innerHTML='';
document.getElementById('dx-list').innerHTML='';document.getElementById('priority-list').innerHTML='';
document.getElementById('ai-input').value='';document.getElementById('ai-result').innerHTML='';
_dr=[];calcGCS();calcIMT();
document.getElementById('modal-clear').style.display='none';toast('Semua data berhasil dihapus');
}

// Export
function openExp(){if(!_dr.length){toast('Jalankan analisis dulu','e');return}document.getElementById('modal-export').style.display='flex'}
function exportPDF(){document.getElementById('modal-export').style.display='none';toast('Membuat PDF...','i');var el=document.getElementById('export-box');el.innerHTML=buildExp();setTimeout(function(){html2pdf().set({margin:[10,10,10,10],filename:'Asesmen_'+(gv('f-nama')||'Pasien')+'.pdf',html2canvas:{scale:2,useCORS:true},jsPDF:{unit:'mm',format:'a4',orientation:'portrait'}}).from(el).save().then(function(){toast('PDF berhasil diunduh','s');el.innerHTML=''})},300)}
function exportDOC(){document.getElementById('modal-export').style.display='none';toast('Membuat DOC...','i');var h='<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8"><title>Asesmen</title></head><body>'+buildExp()+'</body></html>';var b=new Blob(['\ufeff',h],{type:'application/msword'});var u=URL.createObjectURL(b);var a=document.createElement('a');a.href=u;a.download='Asesmen_'+(gv('f-nama')||'Pasien')+'.doc';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(u);setTimeout(function(){toast('DOC berhasil diunduh','s')},500)}
function printRes(){window.print()}

// Pain
function buildPain(){var c=document.getElementById('pain-scale');var co=['#10b981','#34d399','#6ee7b7','#a3e635','#facc15','#f59e0b','#f97316','#ef4444','#dc2626','#b91c1c','#7f1d1d'];for(var i=0;i<=10;i++){var b=document.createElement('button');b.className='pb';b.textContent=i;b.onclick=function(){painVal=i;document.querySelectorAll('.pb').forEach(function(x){x.classList.remove('sel');x.style.background='';x.style.borderColor='';x.style.color=''});b.classList.add('sel');b.style.background=co[i];b.style.borderColor=co[i];b.style.color='#fff'};c.appendChild(b)}}
function calcGCS(){var t=+gv('f-gcs-e')+ +gv('f-gcs-v')+ +gv('f-gcs-m');document.getElementById('f-gcs-total').value=t;document.getElementById('f-gcs-total').style.color=t<=8?'var(--danger)':t<=12?'var(--warn)':'var(--accent)'}
function calcIMT(){var bb=+gv('f-bb'),tb=+gv('f-tb')/100;if(bb>0&&tb>0){var im=(bb/(tb*tb)).toFixed(1);document.getElementById('f-imt').value=im;document.getElementById('f-imtkat').value=im<18.5?'Kurus':im<25?'Normal':im<30?'Gemuk':'Obesitas'}else{document.getElementById('f-imt').value='';document.getElementById('f-imtkat').value=''}}
function aLR(){labC++;var d=document.createElement('div');d.className='g3';d.innerHTML='<div class="fg"><input class="fi lp" placeholder="Parameter"></div><div class="fg"><input class="fi lv" placeholder="Nilai"></div><div class="fg"><input class="fi ln" placeholder="Normal"></div>';document.getElementById('lab-rows').appendChild(d)}
function aRR(){roxC++;var d=document.createElement('div');d.className='g2';d.innerHTML='<div class="fg"><input class="fi rt" placeholder="Jenis pemeriksaan"></div><div class="fg"><input class="fi rr" placeholder="Hasil"></div>';document.getElementById('rox-rows').appendChild(d)}
function gLD(){var r=[];document.querySelectorAll('#lab-rows .g3').forEach(function(d){var p=d.querySelector('.lp').value.trim(),v=d.querySelector('.lv').value.trim(),n=d.querySelector('.ln').value.trim();if(p||v)r.push({p:p,v:v,n:n})});return r}
function gRD(){var r=[];document.querySelectorAll('#rox-rows .g2').forEach(function(d){var t=d.querySelector('.rt').value.trim(),res=d.querySelector('.rr').value.trim();if(t||res)r.push({t:t,res:res})});return r}

