// Gather
function gather(){
var d={s:[],o:[]};
var nm=gv('f-nama');if(nm)d.s.push('Pasien '+nm);
var kl=gv('f-keluhan');if(kl)d.s.push(kl);
if(painVal>=0){d.s.push('Skala nyeri '+painVal+'/10');var lk=gv('f-loknyeri');if(lk)d.s.push('Lokasi: '+lk);var dr=gv('f-durasinyeri');if(dr)d.s.push('Durasi: '+dr);var kr=gcv('chk-karnyeri');if(kr.length)d.s.push('Karakteristik: '+kr.join(', '))}
var rs=gv('f-riwayatsekarang');if(rs)d.s.push(rs);
var rd=gcv('chk-riwayatdahulu');if(rd.length)d.s.push('Riwayat dahulu: '+rd.join(', '));
var al=gv('f-alergi');if(al)d.s.push('Alergi: '+al);
var rk=gcv('chk-keluarga');if(rk.length)d.s.push('Riwayat keluarga: '+rk.join(', '));
var na=gv('f-nafsuafter');if(na&&na!=='Baik')d.s.push('Nafsu makan: '+na);
var km=gcv('chk-kesulitanmakan');if(km.length)d.s.push('Kesulitan makan: '+km.join(', '));
var gt=gcv('chk-ganggtidur');if(gt.length)d.s.push('Gangguan tidur: '+gt.join(', '));
var tk=gv('f-tidurkualitas');if(tk&&tk!=='Baik')d.s.push('Kualitas tidur: '+tk);
var td2=gv('f-tidurdurasi');if(td2)d.s.push('Durasi tidur: '+td2+' jam');
var mb=gv('f-mobilisasi');if(mb&&mb!=='Mobile penuh'&&mb!=='Jalan mandiri')d.s.push('Mobilisasi: '+mb);
var v,vs=['f-td|TD |mmHg','f-nadi|Nadi |x/mnt','f-rr|RR |x/mnt','f-suhu|Suhu |°C','f-spo2|SpO2 |%','f-bb|BB |kg','f-tb|TB |cm'];
vs.forEach(function(x){var p=x.split('|');v=gv(p[0]);if(v)d.o.push(p[1]+v)});
var im=gv('f-imt');if(im)d.o.push('IMT '+im+' ('+gv('f-imtkat')+')');
var gc=gv('f-gcs-total');if(gc)d.o.push('GCS '+gc);
var ub=gv('f-ubahbb');if(ub&&ub!=='Tetap')d.o.push('Perubahan BB: '+ub);
var bk=gcv('chk-bak');if(bk.length)d.o.push('Kelainan BAK: '+bk.join(', '));
var bab=gcv('chk-bab');if(bab.length)d.o.push('Kelainan BAB: '+bab.join(', '));
var hy=gcv('chk-hygiene');if(hy.length)d.o.push('Hygiene: '+hy.join(', '));
[['pf-kepala','Kepala & Leher'],['pf-paru','Paru'],['pf-jantung','Jantung'],['pf-abdomen','Abdomen'],['pf-ekstremitas','Ekstremitas'],['pf-kulit','Kulit'],['pf-neuro','Neurologis']].forEach(function(p){var val=gv('f-'+p[0]);if(val)d.o.push(p[1]+': '+val)});
gLD().forEach(function(l){d.o.push('Lab '+l.p+': '+l.v+(l.n?' (normal: '+l.n+')':''))});
gRD().forEach(function(r){d.o.push(r.t+': '+r.res)});
var ek=gv('f-ekg');if(ek)d.o.push('EKG: '+ek);
var lp=gv('f-lainpenunjang');if(lp)d.o.push(lp);
var iv=gv('f-ivfd');if(iv)d.o.push('IVFD: '+iv);
return d;
}

function analyze(data){
var all=data.s.concat(data.o).join(' ').toLowerCase(),results=[];
DB.forEach(function(dx){
var sc=0;dx.kw.forEach(function(kw){if(all.indexOf(kw.toLowerCase())>=0)sc++});
if(sc>0){var pr=dx.bp;if(dx.id==='00030'){var s=+gv('f-spo2');if(s&&s<90)pr=1}if(dx.id==='00199'&&painVal>=7)pr=2;if(dx.id==='RJ'){var g=+gv('f-gcs-total');if(g&&g<=12)pr=1}if(dx.id==='00002'){var i=+gv('f-imt');if(i&&i<17)pr=1}
results.push({id:dx.id,lb:dx.lb,dom:dx.dom,def:dx.def,isR:dx.isR,kw:dx.kw,bp:dx.bp,slki:dx.slki,siki:dx.siki,ms:sc,fp:pr})}
});
results.sort(function(a,b){return a.fp-b.fp||b.ms-a.ms});return results;
}

// AI
function runAI(){var t=document.getElementById('ai-input').value.trim();if(!t){toast('Tempelkan teks dulu','e');return}var l=t.toLowerCase(),r=[];DB.forEach(function(dx){var s=0;dx.kw.forEach(function(k){if(l.indexOf(k.toLowerCase())>=0)s++});if(s>0)r.push({id:dx.id,lb:dx.lb,dom:dx.dom,def:dx.def,isR:dx.isR,slki:dx.slki,siki:dx.siki,ms:s,kw:dx.kw,bp:dx.bp})});r.sort(function(a,b){return b.ms-a.ms});if(!r.length){document.getElementById('ai-result').innerHTML='<div style="padding:20px;text-align:center;color:var(--muted)">Tidak ditemukan diagnosis cocok.</div>';return}var h='<div style="margin-top:12px"><div style="font-size:12px;font-weight:700;margin-bottom:10px;color:var(--accent);display:flex;align-items:center;gap:6px"><span class="pd"></span> '+r.length+' diagnosis ditemukan:</div>';r.forEach(function(x){h+='<div class="am" onclick="expandAI(\''+x.id+'\')"><span><b>'+x.lb+'</b> <span style="color:var(--muted);font-size:10px">('+x.id+')</span></span><span class="ms">'+x.ms+' kw</span></div>'});h+='</div>';document.getElementById('ai-result').innerHTML=h;toast('AI: '+r.length+' diagnosis','s')}
function expandAI(id){var dx=DB.find(function(d){return d.id===id});if(!dx)return;var ex=document.querySelector('.aid-'+id);if(ex){ex.remove();return}var h='<div class="aid-'+id+'" style="margin-top:12px;padding:16px;background:var(--card);border:1px solid var(--border);border-radius:11px;box-shadow:var(--shadow)"><div style="font-weight:700;font-size:14px;margin-bottom:4px">'+dx.lb+' <span style="color:var(--muted);font-size:11px">('+dx.id+') — '+dx.dom+'</span></div><div style="font-size:12px;color:var(--text2);margin-bottom:12px">'+dx.def+'</div>';dx.slki.forEach(function(s){h+='<div class="dxs dxs-s"><div class="dxst" style="color:var(--accent)"><i class="fas fa-bullseye"></i> SLKI: '+s.lb+'</div>';s.ind.forEach(function(i){h+='<div class="ir"><span>'+i+'</span><span>Skala 1-5</span></div>'});h+='</div>'});dx.siki.forEach(function(s){h+='<div class="dxs dxs-k"><div class="dxst" style="color:var(--purple)"><i class="fas fa-hand-holding-medical"></i> SIKI: '+s.lb+'</div>';s.act.forEach(function(a){h+='<div class="ai">'+a+'</div>'});h+='</div>'});h+='</div>';var div=document.createElement('div');div.className='aid-'+id;div.innerHTML=h;document.getElementById('ai-result').appendChild(div)}

// Tabel analisis
function mkTbl(lbl,items){if(!items.length)return'<div class="dt-e">Data '+lbl.toLowerCase()+' belum diisi</div>';var h='<table class="dt"><thead><tr><th class="no">No</th><th class="lb">'+lbl+'</th><th>Data</th></tr></thead><tbody>';items.forEach(function(s,i){h+='<tr><td class="no">'+(i+1)+'</td><td class="lb">'+lbl+'</td><td class="vl">'+s+'</td></tr>'});return h+'</tbody></table>'}

function runAnalysis(){
var data=gather(),results=analyze(data);
document.getElementById('analisa-s').style.display='block';
document.getElementById('data-s').innerHTML=mkTbl('Data Subyektif',data.s);
document.getElementById('analisa-o').style.display='block';
document.getElementById('data-o').innerHTML=mkTbl('Data Obyektif',data.o);
document.getElementById('analisa-m').style.display='block';
if(!results.length){document.getElementById('data-masalah').innerHTML='<div class="dt-e">Belum teridentifikasi masalah. Lengkapi data asesmen.</div>'}
else{var pc={1:'var(--danger)',2:'var(--warn)',3:'var(--teal)',4:'var(--purple)'},bc={1:'b-h',2:'b-m',3:'b-l',4:'b-v'},pl={1:'P1 — Mengancam Jiwa',2:'P2 — Bahaya',3:'P3 — Kenyamanan',4:'P4 — Psikologis'};
var h='<table class="dt"><thead><tr><th class="no">No</th><th class="lb">Diagnosis</th><th>Kode</th><th>Domain</th><th>Prioritas</th><th>Match</th></tr></thead><tbody>';
results.forEach(function(r,i){h+='<tr><td class="no">'+(i+1)+'</td><td class="vl" style="font-weight:600">'+r.lb+(r.isR?' <span class="badge b-a">Risiko</span>':'')+'</td><td class="vl">'+r.id+'</td><td class="vl">'+r.dom+'</td><td><span class="badge '+bc[r.fp]+'">'+pl[r.fp]+'</span></td><td class="vl" style="color:var(--accent);font-weight:700">'+r.ms+'</td></tr>'});
h+='</tbody></table>';document.getElementById('data-masalah').innerHTML=h}
_dr=results;toast('Analisis: '+results.length+' masalah','s');
}

