// Form helpers
function fld(id,label,type,opts,max,extra){
if(type==='sel'){var h='<div class="fg"><label class="fl">'+label+'</label><select id="'+id+'" class="fs">';opts.forEach(function(o){h+='<option value="'+o+'">'+o+'</option>'});return h+'</select></div>'}
var a='id="'+id+'" class="fi" placeholder="'+label+'"';if(max)a+=' maxlength="'+max+'"';if(extra)a+=' '+extra;
if(type==='date')a='id="'+id+'" type="date" class="fi"';
if(type==='number')a='id="'+id+'" type="number" class="fi" placeholder="'+label+'"';
return'<div class="fg"><label class="fl">'+label+'</label><input '+a+'></div>'}
